import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { PlusCircle, Trash2, Search, Filter, Wallet, TrendingUp, TrendingDown } from 'lucide-react';

const API_BASE = 'http://localhost:5000/api';

function App() {
    const [transactions, setTransactions] = useState([]);
    const [dailySummary, setDailySummary] = useState({ income: 0, expense: 0, balance: 0 });
    const [monthlySummary, setMonthlySummary] = useState({ income: 0, expense: 0, balance: 0 });

    // Form State
    const [description, setDescription] = useState('');
    const [amount, setAmount] = useState('');
    const [type, setType] = useState('expense');
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

    // Filters State
    const [search, setSearch] = useState('');
    const [selectedMonth, setSelectedMonth] = useState('');

    const fetchData = async () => {
        try {
            let url = `${API_BASE}/transactions`;
            const params = new URLSearchParams();
            if (search) params.append('search', search);
            if (selectedMonth) params.append('month', selectedMonth);

            const [resTrans, resDaily, resMonthly] = await Promise.all([
                axios.get(`${url}?${params.toString()}`),
                axios.get(`${API_BASE}/summary/daily`),
                axios.get(`${API_BASE}/summary/monthly`)
            ]);

            setTransactions(resTrans.data);
            setDailySummary(resDaily.data);
            setMonthlySummary(resMonthly.data);
        } catch (err) {
            console.error('Error fetching data:', err);
        }
    };

    useEffect(() => {
        fetchData();
    }, [search, selectedMonth]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!description || !amount) return;

        try {
            await axios.post(`${API_BASE}/transactions`, {
                description,
                amount: parseFloat(amount),
                type,
                date
            });
            setDescription('');
            setAmount('');
            fetchData();
        } catch (err) {
            console.error('Error adding transaction:', err);
        }
    };

    const handleDelete = async (id) => {
        try {
            await axios.delete(`${API_BASE}/transactions/${id}`);
            fetchData();
        } catch (err) {
            console.error('Error deleting transaction:', err);
        }
    };

    return (
        <div className="container">
            <header className="header">
                <h1>PocketLedger</h1>
                <p style={{ color: 'var(--text-muted)' }}>Smart Finance Tracker</p>
            </header>

            {/* Summary Section */}
            <section className="summaries-grid">
                <div className="card">
                    <h3>Daily Summary</h3>
                    <div className="stats-container">
                        <div className="stat-item">
                            <div className="stat-label">Income</div>
                            <div className="stat-value income">${dailySummary.income.toFixed(2)}</div>
                        </div>
                        <div className="stat-item">
                            <div className="stat-label">Expense</div>
                            <div className="stat-value expense">${dailySummary.expense.toFixed(2)}</div>
                        </div>
                        <div className="stat-item">
                            <div className="stat-label">Balance</div>
                            <div className="stat-value balance">${dailySummary.balance.toFixed(2)}</div>
                        </div>
                    </div>
                </div>

                <div className="card">
                    <h3>Monthly Summary</h3>
                    <div className="stats-container">
                        <div className="stat-item">
                            <div className="stat-label">Income</div>
                            <div className="stat-value income">${monthlySummary.income.toFixed(2)}</div>
                        </div>
                        <div className="stat-item">
                            <div className="stat-label">Expense</div>
                            <div className="stat-value expense">${monthlySummary.expense.toFixed(2)}</div>
                        </div>
                        <div className="stat-item">
                            <div className="stat-label">Balance</div>
                            <div className="stat-value balance">${monthlySummary.balance.toFixed(2)}</div>
                        </div>
                    </div>
                </div>
            </section>

            <div className="main-grid">
                {/* Left Side: Add Transaction */}
                <section>
                    <div className="card">
                        <h3 style={{ marginBottom: '1.5rem' }}>Add Transaction</h3>
                        <form onSubmit={handleSubmit}>
                            <div className="form-group">
                                <label>Description</label>
                                <input
                                    type="text"
                                    value={description}
                                    onChange={(e) => setDescription(e.target.value)}
                                    placeholder="e.g. Coffee"
                                    required
                                />
                            </div>
                            <div className="form-group">
                                <label>Amount</label>
                                <input
                                    type="number"
                                    value={amount}
                                    onChange={(e) => setAmount(e.target.value)}
                                    placeholder="0.00"
                                    required
                                />
                            </div>
                            <div className="form-group">
                                <label>Type</label>
                                <select value={type} onChange={(e) => setType(e.target.value)}>
                                    <option value="expense">Expense</option>
                                    <option value="income">Income</option>
                                </select>
                            </div>
                            <div className="form-group">
                                <label>Date</label>
                                <input
                                    type="date"
                                    value={date}
                                    onChange={(e) => setDate(e.target.value)}
                                />
                            </div>
                            <button type="submit" className="btn btn-primary">
                                <PlusCircle size={20} />
                                Add Transaction
                            </button>
                        </form>
                    </div>
                </section>

                {/* Right Side: Filters & List */}
                <section>
                    <div className="filters-bar">
                        <div className="search-wrapper">
                            <div style={{ position: 'relative' }}>
                                <Search size={18} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
                                <input
                                    type="text"
                                    placeholder="Search description..."
                                    style={{ paddingLeft: '2.5rem' }}
                                    value={search}
                                    onChange={(e) => setSearch(e.target.value)}
                                />
                            </div>
                        </div>
                        <div className="filter-wrapper">
                            <input
                                type="month"
                                value={selectedMonth}
                                onChange={(e) => setSelectedMonth(e.target.value)}
                            />
                        </div>
                    </div>

                    <div className="transaction-list">
                        {transactions.length === 0 ? (
                            <p style={{ textAlign: 'center', color: 'var(--text-muted)', marginTop: '2rem' }}>No transactions found.</p>
                        ) : (
                            transactions.map((t) => (
                                <div key={t._id} className={`transaction-item ${t.type}`}>
                                    <div className="item-info">
                                        <h4>{t.description}</h4>
                                        <p>{new Date(t.date).toLocaleDateString()}</p>
                                    </div>
                                    <div className="item-actions">
                                        <span className={`item-amount ${t.type}`}>
                                            {t.type === 'income' ? '+' : '-'}${t.amount.toFixed(2)}
                                        </span>
                                        <button onClick={() => handleDelete(t._id)} className="delete-btn">
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </section>
            </div>
        </div>
    );
}

export default App;
